mapper.update:
UPDATE account_import_batch
SET imported_rows     = #{imported},
    duplicate_rows    = #{duplicate},
    format_error_rows = #{formatError}
WHERE id = #{batchId}

mapper.select:
SELECT * FROM account_import_batch
WHERE id = #{id}
  AND deleted_at IS NULL

mapper.sql:
b.deleted_at IS NULL
AND b.id = #{id}
AND b.source_file_name LIKE CONCAT('%', #{sourceFileName}, '%')
AND b.import_format = #{importFormat}
AND b.account_group_id = #{accountGroupId}
AND b.device_os = #{deviceOs}
AND b.account_type = #{accountType}
AND b.status = #{status}



      AND EXISTS (
        SELECT 1
        FROM account_import_detail d
        WHERE d.batch_id = b.id
          AND d.tenant_id = b.tenant_id
          AND d.login_result IN (2, 3, 4)
      )


      AND NOT EXISTS (
        SELECT 1
        FROM account_import_detail d
        WHERE d.batch_id = b.id
          AND d.tenant_id = b.tenant_id
          AND d.login_result IN (2, 3, 4)
      )
